import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Input, dispatchAppToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { bhService } from '../../../services/bh/bhService';
import type { OrderLineDto } from '../../../services/bh/models';
import type { CustomerDto } from '../../../services/master/models';
import { DocumentFormHeader, ValidationErrorBanner } from '../../../components/layout';
import { OrderLinesGrid, UnsavedChangesModal, useMaterialLinesSelection } from '../../../components/form';
import { CustomerSearchField } from '../../../components/search';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { customerFieldHandlers, loadCustomerDisplay } from '../../../utils/customerField';
import {
  collectOrderBannerMessages,
  insertOrderLineFieldErrors,
  shiftOrderLineFieldErrors,
  scrollToFirstOrderFieldError,
  validateOrderFields,
  validateOrderHeaderField,
  validateOrderLineField,
  type OrderFieldErrors,
  type OrderLineFieldKey,
} from '../../../utils/orderFieldValidation';
import { emptyOrderLine, normalizeOrderLines, orderLinesTotal } from '../../../utils/orderLines';
import {
  SalesVoucherFormFooter,
  SalesVoucherFormShell,
  SalesVoucherHeaderSection,
  VoucherFormRow,
} from '../../../components/voucher';
import { useSalesFormProcessingLevel } from '../../../hooks/useSalesFormProcessingLevel';
import { useUnsavedChangesGuard } from '../../../hooks/useUnsavedChangesGuard';
import df from '../../../styles/documentForm.module.css';

const TEST_ID = 'don-hang';

type FormSnapshot = {
  orderDate: string;
  customerId: string;
  description: string;
  lines: OrderLineDto[];
};

function buildSnapshot(state: FormSnapshot): string {
  return JSON.stringify(state);
}

function nextLinesHasValidLine(
  lines: OrderLineDto[],
  idx: number,
  updated: OrderLineDto,
): boolean {
  const merged = lines.map((l, i) => (i === idx ? updated : l));
  return merged.some(l => l.materialCode?.trim() && Number(l.quantity) > 0);
}

const DonHangFormPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const isEdit = Boolean(id);
  const isNew = !isEdit;
  const navigate = useNavigate();
  const dispatch = useAppDispatch();
  const tid = (suffix: string) => `${TEST_ID}-${suffix}`;
  const validationBannerId = tid('validation-banner');
  const initFormName = isEdit ? 'edit-sales-order' : 'create-sales-order';
  const {
    processingLevel,
    setProcessingLevel,
    processingLevelOptions,
  } = useSalesFormProcessingLevel(initFormName);
  const [orderDate, setOrderDate] = useState(new Date().toISOString().slice(0, 10));
  const [customerId, setCustomerId] = useState('');
  const [customerCode, setCustomerCode] = useState('');
  const [customerName, setCustomerName] = useState('');
  const [description, setDescription] = useState('');
  const [lines, setLines] = useState<OrderLineDto[]>([emptyOrderLine()]);
  const [loading, setLoading] = useState(isEdit);
  const [saving, setSaving] = useState(false);
  const [headerExpanded, setHeaderExpanded] = useState(true);
  const [savedSnapshot, setSavedSnapshot] = useState('');
  const [fieldErrors, setFieldErrors] = useState<OrderFieldErrors>({});
  const [validationErrors, setValidationErrors] = useState<string[]>([]);
  const [bannerClosed, setBannerClosed] = useState(false);
  const [bannerExpanded, setBannerExpanded] = useState(true);
  const savedStateRef = useRef<FormSnapshot | null>(null);

  const applySnapshot = useCallback((snap: FormSnapshot) => {
    savedStateRef.current = snap;
    setSavedSnapshot(buildSnapshot(snap));
  }, []);

  const currentSnapshot = buildSnapshot({
    orderDate,
    customerId,
    description,
    lines,
  });
  const isDirty = Boolean(savedSnapshot) && currentSnapshot !== savedSnapshot;

  const { guardedAction, showUnsavedModal, confirmLeave, cancelLeave } = useUnsavedChangesGuard(isDirty);

  useEffect(() => {
    setValidationErrors(collectOrderBannerMessages(fieldErrors));
    if (Object.keys(fieldErrors).length === 0) {
      setBannerClosed(false);
    }
  }, [fieldErrors]);

  const handleBack = useCallback(() => {
    guardedAction(() => navigate('/bh/dh'));
  }, [guardedAction, navigate]);

  const patchHeaderFieldError = useCallback((
    key: 'orderDate' | 'customerId',
    value: string,
  ) => {
    setFieldErrors(prev => {
      const msg = validateOrderHeaderField(key, value);
      const next = { ...prev, [key]: msg };
      if (!msg) delete next[key];
      return next;
    });
    setBannerClosed(false);
  }, []);

  const patchLineFieldError = useCallback((
    lineIndex: number,
    key: OrderLineFieldKey,
    line: OrderLineDto,
  ) => {
    setFieldErrors(prev => {
      const msg = validateOrderLineField(lineIndex, key, line);
      const nextLines = { ...prev.lines };
      const row = { ...(nextLines[lineIndex] ?? {}) };
      if (msg) row[key] = msg;
      else delete row[key];
      if (Object.keys(row).length > 0) nextLines[lineIndex] = row;
      else delete nextLines[lineIndex];
      const next: OrderFieldErrors = {
        ...prev,
        lines: Object.keys(nextLines).length > 0 ? nextLines : undefined,
      };
      if (next.linesGeneral && line.materialCode?.trim() && Number(line.quantity) > 0) {
        delete next.linesGeneral;
      }
      return next;
    });
    setBannerClosed(false);
  }, []);

  const baseCustomerHandlers = useMemo(
    () => customerFieldHandlers(setCustomerId, setCustomerCode, setCustomerName),
    [],
  );

  const customerHandlers = useMemo(
    () => ({
      onSelect: (customer: CustomerDto) => {
        baseCustomerHandlers.onSelect(customer);
        patchHeaderFieldError('customerId', customer.customerId);
      },
      onClear: () => {
        baseCustomerHandlers.onClear();
        patchHeaderFieldError('customerId', '');
      },
    }),
    [baseCustomerHandlers, patchHeaderFieldError],
  );

  const { copyLine, lineRowProps, setSelectedLineIndex } = useMaterialLinesSelection(lines, setLines);

  useEffect(() => {
    if (!isNew || savedSnapshot) return;
    applySnapshot({
      orderDate,
      customerId,
      description,
      lines,
    });
  }, [
    isNew,
    savedSnapshot,
    orderDate,
    customerId,
    description,
    lines,
    applySnapshot,
  ]);

  useEffect(() => {
    if (!id) return;
    let cancelled = false;
    const t = setTimeout(() => {
      bhService.getOrder(id)
        .then(async o => {
          if (cancelled) return;
          setOrderDate(o.orderDate.slice(0, 10));
          setCustomerId(o.customerId);
          setDescription(o.description ?? '');
          const mappedLines = o.lines?.length ? o.lines : [emptyOrderLine()];
          setLines(mappedLines);
          const display = await loadCustomerDisplay(o.customerId, o.customerName);
          if (!cancelled) {
            setCustomerCode(display.code);
            setCustomerName(display.name);
            applySnapshot({
              orderDate: o.orderDate.slice(0, 10),
              customerId: o.customerId,
              description: o.description ?? '',
              lines: mappedLines,
            });
          }
        })
        .catch(err => { if (!cancelled) dispatchAppToast(dispatch, { message: getApiErrorMessage(err, 'Lỗi tải đơn hàng'), type: 'error' }); })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [id, dispatch, applySnapshot]);

  const handleLinesChange = useCallback((nextLines: OrderLineDto[]) => {
    setLines(nextLines);
  }, []);

  const handleAfterLineUpdate = useCallback((
    idx: number,
    line: OrderLineDto,
    key: OrderLineFieldKey,
  ) => {
    patchLineFieldError(idx, key, line);
    setFieldErrors(prev => {
      if (!prev.linesGeneral) return prev;
      const hasValid = nextLinesHasValidLine(lines, idx, line);
      if (!hasValid) return prev;
      const next = { ...prev };
      delete next.linesGeneral;
      return next;
    });
  }, [patchLineFieldError, lines]);

  const addLine = () => {
    const insertAt = lines.length;
    setLines(prev => [...prev, emptyOrderLine()]);
    setFieldErrors(prev => ({
      ...prev,
      lines: insertOrderLineFieldErrors(prev.lines, insertAt),
    }));
    setSelectedLineIndex(lines.length);
  };

  const removeLine = (idx: number) => {
    setLines(prev => {
      const next = prev.filter((_, i) => i !== idx);
      return next.length ? next : [emptyOrderLine()];
    });
    setFieldErrors(prev => ({
      ...prev,
      lines: shiftOrderLineFieldErrors(prev.lines, idx),
    }));
    setSelectedLineIndex(Math.max(0, idx - 1));
  };

  const handleSave = async () => {
    const validation = validateOrderFields({
      isNew,
      orderDate,
      customerId,
      lines,
    });
    if (validation.bannerMessages.length > 0) {
      setFieldErrors(validation.fieldErrors);
      setBannerClosed(false);
      setBannerExpanded(true);
      scrollToFirstOrderFieldError(validation.fieldErrors, tid, validationBannerId);
      return;
    }
    setFieldErrors({});
    const normalized = normalizeOrderLines(lines);
    setSaving(true);
    try {
      if (isEdit && id) {
        await bhService.updateOrder(id, { description, lines: normalized });
        dispatchAppToast(dispatch, { message: 'Cập nhật đơn hàng thành công', type: 'success' });
      } else {
        await bhService.createOrder({ orderDate, customerId, description, lines: normalized });
        dispatchAppToast(dispatch, { message: 'Tạo đơn hàng thành công', type: 'success' });
      }
      navigate('/bh/dh');
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: getApiErrorMessage(err, 'Lưu thất bại'), type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <div className={df.loading}>Đang tải...</div>;

  const total = orderLinesTotal(lines);

  return (
    <>
      <SalesVoucherFormShell
        testIdPrefix={TEST_ID}
        header={(
          <DocumentFormHeader
            onBack={handleBack}
            title={isEdit ? 'Sửa đơn hàng' : 'Tạo đơn hàng'}
            isNew={isNew}
            saving={saving}
            saveLabel="Tạo đơn hàng"
            saveEditLabel="Lưu thay đổi"
            onSave={handleSave}
          />
        )}
        footer={(
          <SalesVoucherFormFooter
            testIdPrefix={TEST_ID}
            totals={[{ label: 'Tổng cộng:', amount: total }]}
            processingLevel={processingLevel}
            onProcessingLevelChange={setProcessingLevel}
            processingLevelOptions={processingLevelOptions}
            processingLevelDisabled={isEdit}
          />
        )}
      >
        <ValidationErrorBanner
          id={validationBannerId}
          data-testid={validationBannerId}
          errors={validationErrors}
          closed={bannerClosed}
          expanded={bannerExpanded}
          onToggle={() => setBannerExpanded(v => !v)}

          onClose={() => setBannerClosed(true)}
        />

        <SalesVoucherHeaderSection
          title="Thông tin đơn hàng"
          testIdPrefix={TEST_ID}
          headerExpanded={headerExpanded}
          setHeaderExpanded={setHeaderExpanded}
        >
          {({ fieldClass, compactHideClass, formRowStyles }) => (
            <VoucherFormRow styles={formRowStyles}>
              <div
                className={fieldClass(compactHideClass(true))}
                data-validation-target={fieldErrors.orderDate ? 'true' : undefined}
              >
                <label className={df.label}>Ngày đặt{isNew ? ' *' : ''}</label>
                <Input
                  id={tid('field-orderDate')}
                  type="date"
                  value={orderDate}
                  error={fieldErrors.orderDate}
                  onChange={e => {
                    const v = e.target.value;
                    setOrderDate(v);
                    if (isNew) patchHeaderFieldError('orderDate', v);
                  }}
                  disabled={isEdit}
                  data-testid={tid('field-orderDate')}
                />
              </div>
              <div
                className={fieldClass(df.spanCol2, compactHideClass(true))}
                data-validation-target={fieldErrors.customerId ? 'true' : undefined}
              >
                <label className={df.label}>Khách hàng{isNew ? ' *' : ''}</label>
                <CustomerSearchField
                  customerId={customerId}
                  customerCode={customerCode}
                  customerName={customerName}
                  onSelect={customerHandlers.onSelect}
                  onClear={customerHandlers.onClear}
                  disabled={isEdit}
                  error={fieldErrors.customerId}
                  testIdPrefix={`${TEST_ID}-customer`}
                />
              </div>
              <div className={fieldClass(compactHideClass(false))}>
                <label className={df.label}>Diễn giải</label>
                <Input
                  value={description}
                  onChange={e => setDescription(e.target.value)}
                  data-testid={tid('field-description')}
                />
              </div>
            </VoucherFormRow>
          )}
        </SalesVoucherHeaderSection>
        <div
          id={tid('lines-section')}
          className={[df.section, df.linesSection].join(' ')}
          data-validation-target={fieldErrors.linesGeneral ? 'true' : undefined}
        >
          <h2 className={df.sectionTitle}>Chi tiết hàng hóa</h2>
          <OrderLinesGrid
            lines={lines}
            canEdit
            lineErrors={fieldErrors.lines}
            linesGeneralError={fieldErrors.linesGeneral}
            testIdPrefix={TEST_ID}
            onChange={handleLinesChange}
            onAfterLineUpdate={handleAfterLineUpdate}
            onAddLine={addLine}
            onCopyLine={copyLine}
            lineRowProps={lineRowProps}
            onRemoveLine={removeLine}
          />
        </div>
      </SalesVoucherFormShell>

      <UnsavedChangesModal
        isOpen={showUnsavedModal}
        onStay={cancelLeave}
        onLeave={confirmLeave}
        data-testid={`${TEST_ID}-unsaved-modal`}
      />
    </>
  );
};

export default DonHangFormPage;
